//! bench-cat-map-image-diffusion -- checkpoint-free cat-map diffusion probe.
//!
//! This does not claim FLUX/Molmo accuracy. It isolates the runtime mechanism:
//! local image diffusion on an n x n torus, with optional Arnold cat-map routing
//! between denoise steps. The route-search mode answers whether the route family
//! contains faster descent directions; fixed-route mode is the plausible fast
//! path because it spends one denoise kernel per step.

use std::process::exit;
use std::time::Instant;

use distributed_inference::cat_map_route::{cat_map_permutation_modulus, CatMapRouteError};

#[derive(Clone, Debug)]
struct Cli {
    size: usize,
    channels: usize,
    max_steps: usize,
    target_ratio: f64,
    alpha: f32,
    seed: u64,
    ticks: Option<Vec<u32>>,
    schedule: Option<Vec<Option<u32>>>,
    max_period_ticks: u32,
    warmup: usize,
    repeats: usize,
}

#[derive(Clone, Debug)]
struct RunStats {
    mode: &'static str,
    repeat: usize,
    ms: u128,
    steps: usize,
    kernel_evals: usize,
    route_evals: usize,
    accepted_routes: usize,
    rejected_routes: usize,
    route_wins: String,
    schedule: String,
    energy_start: f64,
    energy_end: f64,
    max_delta: f32,
    output: Vec<f32>,
}

fn main() {
    let cli = parse_cli();
    validate_cli(&cli);

    let period = cat_map_matrix_period(cli.size as u32, cli.max_period_ticks);
    let ticks = select_ticks(&cli, period);
    let routes = build_routes(cli.size as u32, &ticks)
        .unwrap_or_else(|error| die(format!("build routes: {error:?}")));
    let route_label = ticks
        .iter()
        .map(u32::to_string)
        .collect::<Vec<_>>()
        .join("|");

    eprintln!(
        "[bench-cat-map-image-diffusion] size={} channels={} alpha={} target_ratio={} period={} ticks={}",
        cli.size,
        cli.channels,
        cli.alpha,
        cli.target_ratio,
        period
            .map(|value| value.to_string())
            .unwrap_or_else(|| "unknown".to_string()),
        route_label
    );

    let initial = synthesize_image(cli.size, cli.channels, cli.seed);
    let compiled_schedule = match &cli.schedule {
        Some(schedule) => {
            let steps = resolve_schedule(&routes, schedule);
            let route_wins = count_schedule_route_wins(&routes, &steps);
            CompiledSchedule { steps, route_wins }
        }
        None => compile_route_schedule(&initial, &cli, &routes),
    };
    let compiled_schedule_label = format_schedule(&routes, &compiled_schedule.steps);
    eprintln!(
        "[bench-cat-map-image-diffusion] compiled_schedule steps={} route_wins={} sequence={}",
        compiled_schedule.steps.len(),
        format_route_wins(&routes, &compiled_schedule.route_wins),
        compiled_schedule_label
    );

    for _ in 0..cli.warmup {
        let _ = run_canonical(&initial, &cli, usize::MAX);
        let _ = run_cat_fixed(&initial, &cli, &routes[0], usize::MAX);
        let _ = run_cat_slide(&initial, &cli, &routes, usize::MAX);
        let _ = run_cat_compiled(
            &initial,
            &cli,
            &routes,
            &compiled_schedule.steps,
            usize::MAX,
        );
    }

    println!(
        "mode,size,channels,alpha,target_ratio,repeat,ms,steps,kernel_evals,route_evals,accepted_routes,rejected_routes,period,ticks,route_wins,schedule,energy_start,energy_end,energy_ratio,max_delta,rms_vs_canonical,max_vs_canonical"
    );

    for repeat in 0..cli.repeats {
        let canonical = run_canonical(&initial, &cli, repeat);
        print_stats(&canonical, &canonical, &cli, period, &route_label);

        let fixed = run_cat_fixed(&initial, &cli, &routes[0], repeat);
        print_stats(&fixed, &canonical, &cli, period, &route_label);

        let slide = run_cat_slide(&initial, &cli, &routes, repeat);
        print_stats(&slide, &canonical, &cli, period, &route_label);

        let compiled = run_cat_compiled(&initial, &cli, &routes, &compiled_schedule.steps, repeat);
        print_stats(&compiled, &canonical, &cli, period, &route_label);
    }
}

fn parse_cli() -> Cli {
    let raw: Vec<String> = std::env::args().collect();
    let mut cli = Cli {
        size: 64,
        channels: 4,
        max_steps: 512,
        target_ratio: 0.10,
        alpha: 0.18,
        seed: 42,
        ticks: None,
        schedule: None,
        max_period_ticks: 4096,
        warmup: 1,
        repeats: 3,
    };

    let mut i = 1;
    while i < raw.len() {
        match raw[i].as_str() {
            "--size" => {
                i += 1;
                cli.size = parse_arg(raw.get(i), "--size");
            }
            "--channels" => {
                i += 1;
                cli.channels = parse_arg(raw.get(i), "--channels");
            }
            "--max-steps" => {
                i += 1;
                cli.max_steps = parse_arg(raw.get(i), "--max-steps");
            }
            "--target-ratio" => {
                i += 1;
                cli.target_ratio = parse_arg(raw.get(i), "--target-ratio");
            }
            "--alpha" => {
                i += 1;
                cli.alpha = parse_arg(raw.get(i), "--alpha");
            }
            "--seed" => {
                i += 1;
                cli.seed = parse_arg(raw.get(i), "--seed");
            }
            "--ticks" => {
                i += 1;
                cli.ticks = Some(parse_u32_csv(
                    raw.get(i).unwrap_or_else(|| die("--ticks needs a CSV")),
                ));
            }
            "--schedule" => {
                i += 1;
                cli.schedule = Some(parse_schedule_csv(
                    raw.get(i).unwrap_or_else(|| die("--schedule needs a CSV")),
                ));
            }
            "--max-period-ticks" => {
                i += 1;
                cli.max_period_ticks = parse_arg(raw.get(i), "--max-period-ticks");
            }
            "--warmup" => {
                i += 1;
                cli.warmup = parse_arg(raw.get(i), "--warmup");
            }
            "--repeats" => {
                i += 1;
                cli.repeats = parse_arg(raw.get(i), "--repeats");
            }
            "-h" | "--help" => {
                eprintln!("usage: bench-cat-map-image-diffusion [--size N] [--channels C] [--max-steps N] [--target-ratio R] [--alpha A] [--seed N] [--ticks 1,3,5] [--schedule 48,96,C] [--warmup N] [--repeats N]");
                exit(0);
            }
            other => die(format!("unknown arg {other:?}")),
        }
        i += 1;
    }
    cli
}

fn validate_cli(cli: &Cli) {
    if cli.size < 2 {
        die("--size must be at least 2");
    }
    if cli.channels == 0 {
        die("--channels must be greater than zero");
    }
    if cli.max_steps == 0 {
        die("--max-steps must be greater than zero");
    }
    if !(0.0..1.0).contains(&cli.target_ratio) {
        die("--target-ratio must be in (0, 1)");
    }
    if !cli.alpha.is_finite() || cli.alpha <= 0.0 || cli.alpha >= 0.25 {
        die("--alpha must be finite and in (0, 0.25)");
    }
    if cli.repeats == 0 {
        die("--repeats must be greater than zero");
    }
}

fn parse_arg<T>(value: Option<&String>, name: &str) -> T
where
    T: std::str::FromStr,
    T::Err: std::fmt::Display,
{
    value
        .unwrap_or_else(|| die(format!("{name} needs a value")))
        .parse()
        .unwrap_or_else(|error| die(format!("{name}: {error}")))
}

fn parse_u32_csv(raw: &str) -> Vec<u32> {
    raw.split(',')
        .filter(|part| !part.trim().is_empty())
        .map(|part| {
            part.trim()
                .parse()
                .unwrap_or_else(|error| die(format!("tick {:?}: {error}", part.trim())))
        })
        .collect()
}

fn parse_schedule_csv(raw: &str) -> Vec<Option<u32>> {
    raw.split(',')
        .filter(|part| !part.trim().is_empty())
        .map(|part| match part.trim() {
            "C" | "c" | "canonical" => None,
            tick => Some(
                tick.parse()
                    .unwrap_or_else(|error| die(format!("schedule tick {tick:?}: {error}"))),
            ),
        })
        .collect()
}

fn select_ticks(cli: &Cli, period: Option<u32>) -> Vec<u32> {
    if let Some(ticks) = &cli.ticks {
        if ticks.is_empty() {
            die("--ticks must contain at least one tick");
        }
        return unique_ticks(ticks.iter().copied(), period);
    }

    match period {
        Some(p) if p > 1 => unique_ticks(
            [1, p / 8, p / 4, p / 2, p.saturating_sub(1)].into_iter(),
            Some(p),
        ),
        _ => unique_ticks([1, 3, 5, 9, 17, 33].into_iter(), None),
    }
}

fn unique_ticks<I>(ticks: I, period: Option<u32>) -> Vec<u32>
where
    I: Iterator<Item = u32>,
{
    let mut out = Vec::new();
    for tick in ticks {
        let normalized = match period {
            Some(p) if p > 0 => tick % p,
            _ => tick,
        };
        if normalized > 0 && !out.contains(&normalized) {
            out.push(normalized);
        }
    }
    if out.is_empty() {
        out.push(1);
    }
    out
}

fn build_routes(modulus: u32, ticks: &[u32]) -> Result<Vec<Route>, CatMapRouteError> {
    let mut routes = Vec::with_capacity(ticks.len());
    for &tick in ticks {
        routes.push(Route {
            tick,
            permutation: cat_map_permutation_modulus(modulus, tick)?,
        });
    }
    Ok(routes)
}

fn resolve_schedule(routes: &[Route], schedule: &[Option<u32>]) -> Vec<Option<usize>> {
    schedule
        .iter()
        .map(|tick| {
            tick.map(|tick| {
                routes
                    .iter()
                    .position(|route| route.tick == tick)
                    .unwrap_or_else(|| die(format!("schedule tick {tick} is not in --ticks")))
            })
        })
        .collect()
}

fn count_schedule_route_wins(routes: &[Route], schedule: &[Option<usize>]) -> Vec<usize> {
    let mut wins = vec![0usize; routes.len()];
    for route_index in schedule.iter().flatten() {
        wins[*route_index] += 1;
    }
    wins
}

#[derive(Clone, Debug)]
struct Route {
    tick: u32,
    permutation: Vec<usize>,
}

#[derive(Clone, Debug)]
struct CompiledSchedule {
    steps: Vec<Option<usize>>,
    route_wins: Vec<usize>,
}

fn run_canonical(initial: &[f32], cli: &Cli, repeat: usize) -> RunStats {
    let energy_start = gradient_energy(initial, cli.size, cli.channels);
    let target = energy_start * cli.target_ratio;
    let mut current = initial.to_vec();
    let mut next = vec![0.0f32; initial.len()];
    let mut energy = energy_start;
    let mut max_delta = 0.0f32;
    let started = Instant::now();
    let mut steps = 0;
    while steps < cli.max_steps && energy > target {
        max_delta = diffuse_step(&current, &mut next, cli.size, cli.channels, cli.alpha);
        std::mem::swap(&mut current, &mut next);
        energy = gradient_energy(&current, cli.size, cli.channels);
        steps += 1;
    }
    RunStats {
        mode: "canonical",
        repeat,
        ms: started.elapsed().as_millis(),
        steps,
        kernel_evals: steps,
        route_evals: 0,
        accepted_routes: 0,
        rejected_routes: 0,
        route_wins: String::new(),
        schedule: String::new(),
        energy_start,
        energy_end: energy,
        max_delta,
        output: current,
    }
}

fn run_cat_fixed(initial: &[f32], cli: &Cli, route: &Route, repeat: usize) -> RunStats {
    let energy_start = gradient_energy(initial, cli.size, cli.channels);
    let target = energy_start * cli.target_ratio;
    let mut current = initial.to_vec();
    let mut routed = vec![0.0f32; initial.len()];
    let mut routed_next = vec![0.0f32; initial.len()];
    let mut candidate = vec![0.0f32; initial.len()];
    let mut fallback = vec![0.0f32; initial.len()];
    let mut energy = energy_start;
    let mut max_delta = 0.0f32;
    let mut steps = 0;
    let mut kernel_evals = 0;
    let mut route_evals = 0;
    let mut accepted_routes = 0;
    let mut rejected_routes = 0;
    let started = Instant::now();

    while steps < cli.max_steps && energy > target {
        route_with_permutation(&current, &mut routed, cli.channels, route);
        let route_delta =
            diffuse_step(&routed, &mut routed_next, cli.size, cli.channels, cli.alpha);
        unroute_with_permutation(&routed_next, &mut candidate, cli.channels, route);
        kernel_evals += 1;
        route_evals += 1;

        let candidate_energy = gradient_energy(&candidate, cli.size, cli.channels);
        if candidate_energy <= energy {
            max_delta = route_delta;
            std::mem::swap(&mut current, &mut candidate);
            energy = candidate_energy;
            accepted_routes += 1;
        } else {
            max_delta = diffuse_step(&current, &mut fallback, cli.size, cli.channels, cli.alpha);
            kernel_evals += 1;
            let fallback_energy = gradient_energy(&fallback, cli.size, cli.channels);
            if fallback_energy <= energy {
                std::mem::swap(&mut current, &mut fallback);
                energy = fallback_energy;
            }
            rejected_routes += 1;
        }
        steps += 1;
    }

    RunStats {
        mode: "cat_fixed",
        repeat,
        ms: started.elapsed().as_millis(),
        steps,
        kernel_evals,
        route_evals,
        accepted_routes,
        rejected_routes,
        route_wins: format!("{}:{accepted_routes}", route.tick),
        schedule: String::new(),
        energy_start,
        energy_end: energy,
        max_delta,
        output: current,
    }
}

fn run_cat_slide(initial: &[f32], cli: &Cli, routes: &[Route], repeat: usize) -> RunStats {
    let energy_start = gradient_energy(initial, cli.size, cli.channels);
    let target = energy_start * cli.target_ratio;
    let mut current = initial.to_vec();
    let mut best = vec![0.0f32; initial.len()];
    let mut candidate = vec![0.0f32; initial.len()];
    let mut routed = vec![0.0f32; initial.len()];
    let mut routed_next = vec![0.0f32; initial.len()];
    let mut energy = energy_start;
    let mut max_delta = 0.0f32;
    let mut steps = 0;
    let mut kernel_evals = 0;
    let mut route_evals = 0;
    let mut accepted_routes = 0;
    let mut rejected_routes = 0;
    let mut route_wins = vec![0usize; routes.len()];
    let started = Instant::now();

    while steps < cli.max_steps && energy > target {
        let canonical_delta = diffuse_step(&current, &mut best, cli.size, cli.channels, cli.alpha);
        kernel_evals += 1;
        let mut best_energy = gradient_energy(&best, cli.size, cli.channels);
        let mut best_delta = canonical_delta;
        let mut best_route = None;

        for (route_index, route) in routes.iter().enumerate() {
            route_with_permutation(&current, &mut routed, cli.channels, route);
            let route_delta =
                diffuse_step(&routed, &mut routed_next, cli.size, cli.channels, cli.alpha);
            unroute_with_permutation(&routed_next, &mut candidate, cli.channels, route);
            kernel_evals += 1;
            route_evals += 1;

            let candidate_energy = gradient_energy(&candidate, cli.size, cli.channels);
            if candidate_energy < best_energy {
                best_energy = candidate_energy;
                best_delta = route_delta;
                best.copy_from_slice(&candidate);
                best_route = Some(route_index);
            }
        }

        if best_energy > energy {
            break;
        }
        if let Some(route_index) = best_route {
            accepted_routes += 1;
            route_wins[route_index] += 1;
            rejected_routes += routes.len().saturating_sub(1);
        } else {
            rejected_routes += routes.len();
        }
        max_delta = best_delta;
        std::mem::swap(&mut current, &mut best);
        energy = best_energy;
        steps += 1;
    }

    RunStats {
        mode: "cat_slide",
        repeat,
        ms: started.elapsed().as_millis(),
        steps,
        kernel_evals,
        route_evals,
        accepted_routes,
        rejected_routes,
        route_wins: format_route_wins(routes, &route_wins),
        schedule: String::new(),
        energy_start,
        energy_end: energy,
        max_delta,
        output: current,
    }
}

fn compile_route_schedule(initial: &[f32], cli: &Cli, routes: &[Route]) -> CompiledSchedule {
    let energy_start = gradient_energy(initial, cli.size, cli.channels);
    let target = energy_start * cli.target_ratio;
    let mut current = initial.to_vec();
    let mut best = vec![0.0f32; initial.len()];
    let mut candidate = vec![0.0f32; initial.len()];
    let mut routed = vec![0.0f32; initial.len()];
    let mut routed_next = vec![0.0f32; initial.len()];
    let mut energy = energy_start;
    let mut steps = Vec::new();
    let mut route_wins = vec![0usize; routes.len()];

    while steps.len() < cli.max_steps && energy > target {
        diffuse_step(&current, &mut best, cli.size, cli.channels, cli.alpha);
        let mut best_energy = gradient_energy(&best, cli.size, cli.channels);
        let mut best_route = None;

        for (route_index, route) in routes.iter().enumerate() {
            route_with_permutation(&current, &mut routed, cli.channels, route);
            diffuse_step(&routed, &mut routed_next, cli.size, cli.channels, cli.alpha);
            unroute_with_permutation(&routed_next, &mut candidate, cli.channels, route);

            let candidate_energy = gradient_energy(&candidate, cli.size, cli.channels);
            if candidate_energy < best_energy {
                best_energy = candidate_energy;
                best.copy_from_slice(&candidate);
                best_route = Some(route_index);
            }
        }

        if best_energy > energy {
            break;
        }
        if let Some(route_index) = best_route {
            route_wins[route_index] += 1;
        }
        steps.push(best_route);
        std::mem::swap(&mut current, &mut best);
        energy = best_energy;
    }

    CompiledSchedule { steps, route_wins }
}

fn run_cat_compiled(
    initial: &[f32],
    cli: &Cli,
    routes: &[Route],
    schedule: &[Option<usize>],
    repeat: usize,
) -> RunStats {
    let energy_start = gradient_energy(initial, cli.size, cli.channels);
    let target = energy_start * cli.target_ratio;
    let mut current = initial.to_vec();
    let mut routed = vec![0.0f32; initial.len()];
    let mut routed_next = vec![0.0f32; initial.len()];
    let mut candidate = vec![0.0f32; initial.len()];
    let mut fallback = vec![0.0f32; initial.len()];
    let mut energy = energy_start;
    let mut max_delta = 0.0f32;
    let mut steps = 0;
    let mut kernel_evals = 0;
    let mut route_evals = 0;
    let mut accepted_routes = 0;
    let mut rejected_routes = 0;
    let mut route_wins = vec![0usize; routes.len()];
    let started = Instant::now();

    while steps < cli.max_steps && energy > target {
        let scheduled_route = schedule.get(steps).copied().flatten();
        match scheduled_route {
            Some(route_index) => {
                let route = &routes[route_index];
                route_with_permutation(&current, &mut routed, cli.channels, route);
                max_delta =
                    diffuse_step(&routed, &mut routed_next, cli.size, cli.channels, cli.alpha);
                unroute_with_permutation(&routed_next, &mut candidate, cli.channels, route);
                kernel_evals += 1;
                route_evals += 1;

                let candidate_energy = gradient_energy(&candidate, cli.size, cli.channels);
                if candidate_energy <= energy {
                    std::mem::swap(&mut current, &mut candidate);
                    energy = candidate_energy;
                    accepted_routes += 1;
                    route_wins[route_index] += 1;
                } else {
                    max_delta =
                        diffuse_step(&current, &mut fallback, cli.size, cli.channels, cli.alpha);
                    kernel_evals += 1;
                    let fallback_energy = gradient_energy(&fallback, cli.size, cli.channels);
                    if fallback_energy <= energy {
                        std::mem::swap(&mut current, &mut fallback);
                        energy = fallback_energy;
                    }
                    rejected_routes += 1;
                }
            }
            None => {
                max_delta =
                    diffuse_step(&current, &mut fallback, cli.size, cli.channels, cli.alpha);
                kernel_evals += 1;
                let fallback_energy = gradient_energy(&fallback, cli.size, cli.channels);
                if fallback_energy <= energy {
                    std::mem::swap(&mut current, &mut fallback);
                    energy = fallback_energy;
                }
            }
        }
        steps += 1;
    }

    RunStats {
        mode: "cat_compiled",
        repeat,
        ms: started.elapsed().as_millis(),
        steps,
        kernel_evals,
        route_evals,
        accepted_routes,
        rejected_routes,
        route_wins: format_route_wins(routes, &route_wins),
        schedule: format_schedule(routes, schedule),
        energy_start,
        energy_end: energy,
        max_delta,
        output: current,
    }
}

fn diffuse_step(
    input: &[f32],
    output: &mut [f32],
    size: usize,
    channels: usize,
    alpha: f32,
) -> f32 {
    let mut max_delta = 0.0f32;
    for y in 0..size {
        let y_up = if y == 0 { size - 1 } else { y - 1 };
        let y_down = if y + 1 == size { 0 } else { y + 1 };
        for x in 0..size {
            let x_left = if x == 0 { size - 1 } else { x - 1 };
            let x_right = if x + 1 == size { 0 } else { x + 1 };
            for c in 0..channels {
                let idx = image_idx(size, channels, y, x, c);
                let center = input[idx];
                let neighbor_mean = 0.25
                    * (input[image_idx(size, channels, y_up, x, c)]
                        + input[image_idx(size, channels, y_down, x, c)]
                        + input[image_idx(size, channels, y, x_left, c)]
                        + input[image_idx(size, channels, y, x_right, c)]);
                let next = center + alpha * (neighbor_mean - center);
                max_delta = max_delta.max((next - center).abs());
                output[idx] = next;
            }
        }
    }
    max_delta
}

fn gradient_energy(values: &[f32], size: usize, channels: usize) -> f64 {
    let mut sum = 0.0f64;
    for y in 0..size {
        let y_down = if y + 1 == size { 0 } else { y + 1 };
        for x in 0..size {
            let x_right = if x + 1 == size { 0 } else { x + 1 };
            for c in 0..channels {
                let center = values[image_idx(size, channels, y, x, c)] as f64;
                let dx = values[image_idx(size, channels, y, x_right, c)] as f64 - center;
                let dy = values[image_idx(size, channels, y_down, x, c)] as f64 - center;
                sum += dx * dx + dy * dy;
            }
        }
    }
    sum / (size * size * channels) as f64
}

fn route_with_permutation(input: &[f32], output: &mut [f32], channels: usize, route: &Route) {
    let _ = route.tick;
    for (src, &dst) in route.permutation.iter().enumerate() {
        let src_lo = src * channels;
        let dst_lo = dst * channels;
        output[dst_lo..dst_lo + channels].copy_from_slice(&input[src_lo..src_lo + channels]);
    }
}

fn unroute_with_permutation(input: &[f32], output: &mut [f32], channels: usize, route: &Route) {
    let _ = route.tick;
    for (src, &dst) in route.permutation.iter().enumerate() {
        let src_lo = src * channels;
        let dst_lo = dst * channels;
        output[src_lo..src_lo + channels].copy_from_slice(&input[dst_lo..dst_lo + channels]);
    }
}

fn synthesize_image(size: usize, channels: usize, seed: u64) -> Vec<f32> {
    let mut rng = Lcg::new(seed);
    let mut out = vec![0.0f32; size * size * channels];
    for y in 0..size {
        for x in 0..size {
            let xf = x as f32 / size as f32;
            let yf = y as f32 / size as f32;
            for c in 0..channels {
                let cf = c as f32 + 1.0;
                let wave = (std::f32::consts::TAU * (cf * 5.0 * xf + 3.0 * yf)).sin();
                let cross = (std::f32::consts::TAU * (7.0 * xf - cf * 4.0 * yf)).cos();
                let checker = if ((x / 2 + y / 2 + c) & 1) == 0 {
                    1.0
                } else {
                    -1.0
                };
                let noise = rng.next_f32() * 2.0 - 1.0;
                out[image_idx(size, channels, y, x, c)] =
                    0.35 * wave + 0.25 * cross + 0.25 * checker + 0.15 * noise;
            }
        }
    }
    out
}

fn image_idx(size: usize, channels: usize, y: usize, x: usize, c: usize) -> usize {
    (y * size + x) * channels + c
}

fn drift(reference: &[f32], candidate: &[f32]) -> (f32, f32) {
    let mut sum_sq = 0.0f64;
    let mut max_abs = 0.0f32;
    for i in 0..reference.len() {
        let delta = candidate[i] - reference[i];
        sum_sq += (delta as f64) * (delta as f64);
        max_abs = max_abs.max(delta.abs());
    }
    ((sum_sq / reference.len() as f64).sqrt() as f32, max_abs)
}

fn print_stats(
    stats: &RunStats,
    canonical: &RunStats,
    cli: &Cli,
    period: Option<u32>,
    route_label: &str,
) {
    let (rms, max_abs) = drift(&canonical.output, &stats.output);
    let period_label = period
        .map(|value| value.to_string())
        .unwrap_or_else(|| "unknown".to_string());
    println!(
        "{},{},{},{:.6},{:.8},{},{},{},{},{},{},{},{},{},{},{},{:.9},{:.9},{:.9},{:.9},{:.9},{:.9}",
        stats.mode,
        cli.size,
        cli.channels,
        cli.alpha,
        cli.target_ratio,
        stats.repeat,
        stats.ms,
        stats.steps,
        stats.kernel_evals,
        stats.route_evals,
        stats.accepted_routes,
        stats.rejected_routes,
        period_label,
        route_label,
        stats.route_wins,
        stats.schedule,
        stats.energy_start,
        stats.energy_end,
        stats.energy_end / stats.energy_start,
        stats.max_delta,
        rms,
        max_abs
    );
}

fn format_schedule(routes: &[Route], schedule: &[Option<usize>]) -> String {
    schedule
        .iter()
        .map(|route_index| match route_index {
            Some(route_index) => routes[*route_index].tick.to_string(),
            None => "C".to_string(),
        })
        .collect::<Vec<_>>()
        .join("|")
}

fn format_route_wins(routes: &[Route], wins: &[usize]) -> String {
    routes
        .iter()
        .zip(wins)
        .filter(|(_, wins)| **wins > 0)
        .map(|(route, wins)| format!("{}:{wins}", route.tick))
        .collect::<Vec<_>>()
        .join("|")
}

fn cat_map_matrix_period(modulus: u32, max_ticks: u32) -> Option<u32> {
    if modulus == 0 {
        return None;
    }
    let mut a = Matrix2::cat();
    for ticks in 1..=max_ticks {
        if a.is_identity_mod(modulus) {
            return Some(ticks);
        }
        a = a.mul_mod(Matrix2::cat(), modulus);
    }
    None
}

#[derive(Clone, Copy, Debug)]
struct Matrix2 {
    a00: u32,
    a01: u32,
    a10: u32,
    a11: u32,
}

impl Matrix2 {
    const fn cat() -> Self {
        Self {
            a00: 2,
            a01: 1,
            a10: 1,
            a11: 1,
        }
    }

    fn mul_mod(self, rhs: Self, modulus: u32) -> Self {
        let m = modulus as u64;
        let a00 =
            ((self.a00 as u64 * rhs.a00 as u64 + self.a01 as u64 * rhs.a10 as u64) % m) as u32;
        let a01 =
            ((self.a00 as u64 * rhs.a01 as u64 + self.a01 as u64 * rhs.a11 as u64) % m) as u32;
        let a10 =
            ((self.a10 as u64 * rhs.a00 as u64 + self.a11 as u64 * rhs.a10 as u64) % m) as u32;
        let a11 =
            ((self.a10 as u64 * rhs.a01 as u64 + self.a11 as u64 * rhs.a11 as u64) % m) as u32;
        Self { a00, a01, a10, a11 }
    }

    fn is_identity_mod(self, modulus: u32) -> bool {
        self.a00 % modulus == 1 % modulus
            && self.a01.is_multiple_of(modulus)
            && self.a10.is_multiple_of(modulus)
            && self.a11 % modulus == 1 % modulus
    }
}

#[derive(Clone, Copy, Debug)]
struct Lcg {
    state: u64,
}

impl Lcg {
    const fn new(seed: u64) -> Self {
        Self {
            state: seed ^ 0x9e37_79b9_7f4a_7c15,
        }
    }

    fn next_f32(&mut self) -> f32 {
        self.state = self
            .state
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        let value = (self.state >> 40) as u32;
        value as f32 / (1u32 << 24) as f32
    }
}

fn die(msg: impl AsRef<str>) -> ! {
    eprintln!("bench-cat-map-image-diffusion: {}", msg.as_ref());
    exit(2);
}
